import type {RequestHandler} from 'express';
import got from 'got';
export const shadow:RequestHandler=async(req,res,next)=>{
  // Send to legacy in parallel; log diff
  const legacyP=got(`http://legacy${req.url}`,{throwHttpErrors:false}).text();
  const modernRes=await new Promise<string>(resolve=>{const orig=res.json.bind(res);res.json=(body)=>{resolve(JSON.stringify(body));return orig(body);};next();});
  const legacy=await legacyP;
  if(legacy!==modernRes){
    metrics.increment('shadow.mismatch',{endpoint:req.path});
    logger.warn({endpoint:req.path,legacy,modernRes},'shadow mismatch');
  }
};

