async function backfill(){
  let cursor=await loadCheckpoint();
  const batchSize=10000;
  while(true){
    const r=await pool.query(`
      WITH batch AS (
        SELECT id, first_name, last_name FROM users
        WHERE id > $1 AND display_name IS NULL
        ORDER BY id LIMIT $2 FOR UPDATE SKIP LOCKED
      )
      UPDATE users u SET display_name = COALESCE(NULLIF(TRIM(b.first_name || ' ' || COALESCE(b.last_name,'')),''),'User')
      FROM batch b WHERE u.id = b.id RETURNING u.id
    `,[cursor,batchSize]);
    if(r.rowCount===0)break;
    cursor=Math.max(...r.rows.map(x=>x.id));
    await saveCheckpoint(cursor);
    console.log(`processed up to id=${cursor}, batch=${r.rowCount}`);
    await new Promise(r=>setTimeout(r,500));
  }
}

