export async function encryptField(plain:string):Promise<Buffer>{
  const r=await kms.send(new EncryptCommand({KeyId:process.env.KMS_KEY_ID!,Plaintext:Buffer.from(plain)}));
  return Buffer.from(r.CiphertextBlob!);
}
export async function decryptField(cipher:Buffer):Promise<string>{
  const r=await kms.send(new DecryptCommand({CiphertextBlob:cipher}));
  return Buffer.from(r.Plaintext!).toString('utf8');
}

